let func = function (body, data) {
    // ---校验列表
    if (!body.snList || !Array.isArray(body.snList)) {
        return { "err": "error", "snList": [] }; // 不符合规则时返回空数组
    }

    if (body.snList.length < 1) {
        return { "err": "error", "msg": "snList error", "data": body.snList };
    }

    let snObj = {};
    for (let i = 0; i < body.snList.length; i++) {
        let sn = body.snList[i];

        if (typeof sn !== 'string') {
            return { "err": "error", "snList": [] }; // 非字符串元素时返回空数组
        }

        sn = sn.replace(/\r\n/g, "").replace(/\n/g, "").replace(/\r/g, "");

        if (str(sn) || sn.length < 1) { // 合并空字符串校验
            return { "err": "error", "msg": "sn error" };
        }
        if (!snObj[sn]) {
            snObj[sn] = true;
            data.snList = data.snList ? `${data.snList},'${sn}'` : `'${sn}'`; // 优化字符串拼接
        }
    }
    return null; // 只有在没有错误的情况下才返回null，以便于后续处理
}

